// ALL_QUIZZES — 12 quizzes × 15 questions = 180 total
// Using template literals throughout to prevent apostrophe/quote parse errors

export const ALL_QUIZZES = [
  {
    id:'bb01', cat:'Bio/Biochem', title:'Enzyme Kinetics & Michaelis-Menten', diff:'Hard',
    qs:[
      { q:`What does the Michaelis constant (Km) represent?`, ch:[`Maximum reaction velocity`,`Substrate concentration at half-maximal velocity`,`Total enzyme concentration`,`Rate constant for product release`], ans:1, exp:`Km is the substrate concentration [S] at which reaction velocity = Vmax/2. A lower Km indicates higher enzyme affinity for its substrate.` },
      { q:`Competitive inhibition causes which kinetic change?`, ch:[`Decreased Vmax only`,`Increased apparent Km only`,`Decreased Vmax and increased Km`,`Increased Vmax and Km`], ans:1, exp:`Competitive inhibitors compete with substrate for the active site, increasing apparent Km. Vmax is unchanged because excess substrate can overcome the inhibition.` },
      { q:`On a Lineweaver-Burk (double-reciprocal) plot, the y-intercept equals:`, ch:[`Km`,`-1/Km`,`1/Vmax`,`Vmax`], ans:2, exp:`The Lineweaver-Burk plot graphs 1/v vs 1/[S]. Y-intercept = 1/Vmax; x-intercept = -1/Km. This linear transformation allows graphical determination of kinetic constants.` },
      { q:`An uncompetitive inhibitor decreases:`, ch:[`Vmax only`,`Km only`,`Both apparent Vmax and Km`,`Neither Vmax nor Km`], ans:2, exp:`Uncompetitive inhibitors bind only the enzyme-substrate (ES) complex, decreasing both apparent Vmax and apparent Km proportionally. Lineweaver-Burk lines appear parallel to the uninhibited line.` },
      { q:`Catalytic efficiency of an enzyme is best represented by:`, ch:[`Vmax alone`,`Km alone`,`kcat/Km (specificity constant)`,`kcat alone`], ans:2, exp:`The specificity constant kcat/Km measures how efficiently an enzyme converts substrate to product at low [S]. Values near the diffusion limit (~10^8 M-1s-1) indicate a near-perfect enzyme.` },
      { q:`Pure noncompetitive inhibition affects:`, ch:[`Km only`,`Vmax only`,`Both Km and Vmax`,`Neither`], ans:1, exp:`A pure noncompetitive inhibitor binds an allosteric site independent of substrate binding, reducing Vmax without changing Km. The enzyme binds substrate normally but cannot complete catalysis as effectively.` },
      { q:`Which inhibitor type produces parallel lines on a Lineweaver-Burk plot?`, ch:[`Competitive`,`Noncompetitive`,`Uncompetitive`,`Mixed`], ans:2, exp:`Uncompetitive inhibition decreases both Vmax and Km by the same factor (alpha'), giving parallel lines (same slope = Km/Vmax, but different intercepts) on the Lineweaver-Burk plot.` },
      { q:`Allosteric enzymes differ from simple Michaelis-Menten enzymes by exhibiting:`, ch:[`Hyperbolic v vs [S] curves`,`Sigmoidal v vs [S] curves`,`Linear v vs [S] curves`,`No regulation`], ans:1, exp:`Allosteric enzymes show sigmoidal kinetics due to cooperativity between subunits. Binding of substrate (or effector) at one site changes affinity at other sites (positive or negative cooperativity).` },
      { q:`A Hill coefficient greater than 1 indicates:`, ch:[`Competitive inhibition`,`Positive cooperativity`,`Negative cooperativity`,`Irreversible inhibition`], ans:1, exp:`The Hill coefficient n > 1 indicates positive cooperativity — binding of one ligand increases the affinity for subsequent ligands. Hemoglobin has a Hill coefficient of ~2.8 for oxygen binding.` },
      { q:`Feedback inhibition is best described as:`, ch:[`An activator stimulating an early enzyme`,`A product inhibiting an upstream enzyme in its own pathway`,`Covalent modification of the enzyme active site`,`Irreversible binding of a substrate analog`], ans:1, exp:`Feedback (product) inhibition occurs when a downstream metabolite inhibits an earlier, often committed-step, enzyme. This prevents overproduction and conserves cellular resources.` },
      { q:`Vmax is directly proportional to:`, ch:[`Km`,`Substrate concentration`,`Total enzyme concentration [E]t`,`Inhibitor concentration`], ans:2, exp:`Vmax = kcat × [E]total. Doubling enzyme concentration doubles Vmax. kcat (turnover number) is the number of substrate molecules converted per enzyme per second at saturation.` },
      { q:`An enzyme with Km = 0.05 mM has __ affinity compared to an enzyme with Km = 5 mM:`, ch:[`Lower`,`Equal`,`Higher`,`Cannot be determined from Km alone`], ans:2, exp:`Lower Km = higher affinity. The enzyme with Km = 0.05 mM reaches half-maximal velocity at a 100-fold lower substrate concentration than the enzyme with Km = 5 mM.` },
      { q:`Organophosphate compounds (e.g., nerve agents) inhibit acetylcholinesterase by:`, ch:[`Competing with acetylcholine for the active site`,`Forming irreversible covalent bonds with the active-site serine`,`Binding an allosteric site reversibly`,`Increasing the Km for acetylcholine`], ans:1, exp:`Organophosphates irreversibly phosphorylate the active-site serine of acetylcholinesterase. This permanently inactivates the enzyme, causing acetylcholine accumulation at synapses and continuous nerve stimulation.` },
      { q:`The induced-fit model of enzyme catalysis proposes that:`, ch:[`The active site is rigid and perfectly complementary to the substrate`,`Substrate binding induces conformational changes in the enzyme`,`Only one substrate stereoisomer can bind`,`Enzymes never change shape`], ans:1, exp:`The induced-fit model (Koshland, 1958) holds that substrate binding causes conformational changes in the enzyme that optimize the active site geometry for catalysis — more accurate than the original lock-and-key model.` },
      { q:`If enzyme concentration is doubled while all other conditions remain constant, what happens to Km?`, ch:[`Km doubles`,`Km halves`,`Km is unchanged`,`Km increases by the square root of 2`], ans:2, exp:`Km is an intrinsic property of the enzyme-substrate interaction and is independent of enzyme concentration. Only Vmax changes when [E]total changes. Km reflects binding affinity, not enzyme amount.` },
    ]
  },
  {
    id:'bb02', cat:'Bio/Biochem', title:'Glycolysis & Gluconeogenesis', diff:'Hard',
    qs:[
      { q:`What is the net ATP yield from glycolysis of one glucose molecule?`, ch:[`1`,`2`,`4`,`6`], ans:1, exp:`Glycolysis produces 4 ATP but consumes 2 ATP (at hexokinase and PFK-1 steps), giving a net yield of 2 ATP per glucose. It also produces 2 NADH and 2 pyruvate.` },
      { q:`Phosphofructokinase-1 (PFK-1), the key regulatory enzyme of glycolysis, is activated by:`, ch:[`ATP and citrate`,`AMP and fructose-2,6-bisphosphate`,`Glucagon and cAMP`,`High glucose-6-phosphate`], ans:1, exp:`PFK-1 is activated by AMP (low energy) and fructose-2,6-bisphosphate (insulin-stimulated). It is inhibited by ATP, citrate, and H+ — linking glycolytic rate to cellular energy status and pH.` },
      { q:`Which glycolytic enzyme catalyzes the irreversible step that is bypassed in gluconeogenesis by PEPCK?`, ch:[`Aldolase`,`Phosphoglycerate kinase`,`Pyruvate kinase`,`Enolase`], ans:2, exp:`Pyruvate kinase (PEP → pyruvate + ATP) is irreversible. Gluconeogenesis bypasses it using pyruvate carboxylase (pyruvate → OAA) followed by PEPCK (OAA → PEP + CO2).` },
      { q:`Under anaerobic conditions, pyruvate is converted to lactate primarily to:`, ch:[`Produce more ATP`,`Regenerate NAD+ so glycolysis can continue`,`Store energy as lactate`,`Feed into the TCA cycle`], ans:1, exp:`Lactate dehydrogenase regenerates NAD+ from NADH, allowing glycolysis to continue when the ETC cannot accept electrons. No additional ATP is produced; the goal is NAD+ recycling.` },
      { q:`2,3-Bisphosphoglycerate (2,3-BPG) in red blood cells functions to:`, ch:[`Activate PFK-1`,`Stabilize deoxyhemoglobin and reduce oxygen affinity`,`Serve as a glycolytic intermediate that generates ATP`,`Inhibit lactate dehydrogenase`], ans:1, exp:`2,3-BPG binds the central cavity of deoxyhemoglobin (T-state), stabilizing it and shifting the O2 dissociation curve rightward (lower affinity), promoting O2 unloading to tissues.` },
      { q:`Gluconeogenesis occurs primarily in:`, ch:[`Skeletal muscle`,`Heart`,`Liver (and kidney during prolonged fasting)`,`Brain`], ans:2, exp:`The liver provides ~90% of glucose during fasting via gluconeogenesis. Muscle cannot export glucose because it lacks glucose-6-phosphatase. The kidneys contribute ~10-20% during prolonged starvation.` },
      { q:`Which enzyme is unique to gluconeogenesis (not shared with glycolysis)?`, ch:[`Enolase`,`Aldolase`,`Fructose-1,6-bisphosphatase`,`Phosphoglycerate mutase`], ans:2, exp:`Fructose-1,6-bisphosphatase converts F-1,6-BP → F-6-P, bypassing the irreversible PFK-1 step. The other gluconeogenic bypass enzymes are pyruvate carboxylase, PEPCK, and glucose-6-phosphatase.` },
      { q:`The Cori cycle describes:`, ch:[`Glucose-alanine cycling between muscle and liver`,`Lactate shuttling from muscle to liver, where it is converted back to glucose`,`Ketone body production in the liver and utilization in the brain`,`Glycogen synthesis and breakdown in muscle`], ans:1, exp:`In the Cori cycle, exercising muscle produces lactate (anaerobic glycolysis), which travels to the liver. The liver converts lactate to glucose via gluconeogenesis and releases glucose back to muscle.` },
      { q:`Hexokinase (in most tissues) differs from glucokinase (liver/pancreas) in that hexokinase:`, ch:[`Has a higher Km for glucose and is not inhibited by glucose-6-phosphate`,`Has a lower Km and is inhibited by glucose-6-phosphate`,`Requires glucagon for activation`,`Catalyzes an irreversible reaction in gluconeogenesis`], ans:1, exp:`Hexokinase has a low Km (~0.1 mM) and is product-inhibited by G-6-P. Glucokinase has a high Km (~10 mM), is not inhibited by G-6-P, and allows the liver to buffer post-meal glucose spikes.` },
      { q:`Which of the following substrates CANNOT be converted to glucose by gluconeogenesis in mammals?`, ch:[`Alanine`,`Lactate`,`Acetyl-CoA`,`Glycerol`], ans:2, exp:`Acetyl-CoA cannot be converted to glucose in mammals because the pyruvate dehydrogenase reaction is irreversible and mammals lack the glyoxylate cycle. Fatty acid catabolism (acetyl-CoA) cannot contribute to net glucose synthesis.` },
      { q:`Insulin stimulates glycolysis primarily through:`, ch:[`Direct phosphorylation of pyruvate kinase`,`Activating PFK-2, raising fructose-2,6-bisphosphate levels`,`Inhibiting glucokinase`,`Stimulating glucose-6-phosphatase`], ans:1, exp:`Insulin activates protein phosphatase 2A which dephosphorylates (activates) PFK-2. Elevated F-2,6-BP is the most potent allosteric activator of PFK-1, driving glycolytic flux.` },
      { q:`The first ATP-generating reaction in glycolysis is catalyzed by:`, ch:[`Hexokinase`,`Aldolase`,`Phosphoglycerate kinase`,`Pyruvate kinase`], ans:2, exp:`Phosphoglycerate kinase (step 7) catalyzes the first substrate-level phosphorylation: 1,3-bisphosphoglycerate + ADP → 3-phosphoglycerate + ATP. This occurs twice per glucose (once per triose phosphate).` },
      { q:`The committed step of glycolysis is catalyzed by:`, ch:[`Hexokinase`,`Phosphoglucose isomerase`,`PFK-1`,`Aldolase`], ans:2, exp:`PFK-1 catalyzes fructose-6-phosphate → fructose-1,6-bisphosphate, the committed and most heavily regulated step of glycolysis. Once this phosphorylation occurs, the molecule is committed to glycolysis.` },
      { q:`Pyruvate dehydrogenase complex (PDH) is inhibited by:`, ch:[`NAD+ and CoA-SH`,`NADH and acetyl-CoA`,`AMP and ADP`,`Insulin and glucose`], ans:1, exp:`PDH is product-inhibited by NADH and acetyl-CoA, and by ATP. It is activated by NAD+, CoA, AMP, and Ca2+. PDH kinase (inhibitor) is activated by acetyl-CoA and NADH; PDH phosphatase (activator) is activated by insulin and Ca2+.` },
      { q:`Glucose-6-phosphate is a branch point metabolite that can enter:`, ch:[`Glycolysis only`,`Glycolysis and the pentose phosphate pathway`,`Glycolysis, pentose phosphate pathway, and glycogen synthesis`,`Glycolysis and gluconeogenesis simultaneously`], ans:2, exp:`G-6-P is a major metabolic junction: it can enter glycolysis (via PGI), the pentose phosphate pathway (via G-6-P dehydrogenase), glycogen synthesis (via phosphoglucomutase), or be hydrolyzed to glucose by glucose-6-phosphatase in liver/kidney.` },
    ]
  },
  {
    id:'bb03', cat:'Bio/Biochem', title:'TCA Cycle & Electron Transport Chain', diff:'Expert',
    qs:[
      { q:`How many NADH are produced per turn of the TCA cycle?`, ch:[`1`,`2`,`3`,`4`], ans:2, exp:`Each TCA cycle turn produces 3 NADH (at isocitrate dehydrogenase, alpha-ketoglutarate dehydrogenase, and malate dehydrogenase), plus 1 FADH2, 1 GTP, and 2 CO2.` },
      { q:`Citrate synthase condenses acetyl-CoA with which molecule to start the TCA cycle?`, ch:[`Malate`,`Fumarate`,`Oxaloacetate`,`Succinate`], ans:2, exp:`Citrate synthase combines acetyl-CoA (2C) with oxaloacetate (4C) to form citrate (6C) + CoA-SH. This condensation is essentially irreversible and is regulated by product inhibition from citrate, NADH, and succinyl-CoA.` },
      { q:`Alpha-ketoglutarate dehydrogenase is analogous to pyruvate dehydrogenase because it:`, ch:[`Uses the same substrates`,`Catalyzes an oxidative decarboxylation using the same cofactors`,`Is found in the cytoplasm`,`Is activated by NADH`], ans:1, exp:`Both complexes catalyze oxidative decarboxylation using identical cofactors: TPP, lipoic acid, FAD, NAD+, and CoA. Alpha-KG → succinyl-CoA + CO2 + NADH mirrors pyruvate → acetyl-CoA + CO2 + NADH.` },
      { q:`The approximate ATP yield from one acetyl-CoA through the TCA cycle and oxidative phosphorylation is:`, ch:[`2`,`5`,`10`,`16`], ans:2, exp:`1 acetyl-CoA yields 3 NADH (×2.5 ATP = 7.5) + 1 FADH2 (×1.5 ATP = 1.5) + 1 GTP = ~10 ATP total (using updated P/O ratios of 2.5 for NADH and 1.5 for FADH2).` },
      { q:`Which TCA enzyme performs substrate-level phosphorylation?`, ch:[`Citrate synthase`,`Isocitrate dehydrogenase`,`Succinyl-CoA synthetase`,`Succinate dehydrogenase`], ans:2, exp:`Succinyl-CoA synthetase converts succinyl-CoA → succinate, coupling this to GTP synthesis from GDP + Pi. This is the only substrate-level phosphorylation in the TCA cycle (analogous to ATP synthesis in glycolysis).` },
      { q:`Which is NOT a major regulatory enzyme of the TCA cycle?`, ch:[`Isocitrate dehydrogenase`,`Alpha-ketoglutarate dehydrogenase`,`Citrate synthase`,`Fumarase`], ans:3, exp:`Fumarase (fumarate → malate) is not a major regulatory point. The three key regulatory enzymes are citrate synthase, isocitrate dehydrogenase, and alpha-KG dehydrogenase — all inhibited by high NADH/ATP ratios.` },
      { q:`In the ETC, Complex I (NADH dehydrogenase) transfers electrons from NADH to:`, ch:[`Cytochrome c`,`Ubiquinone (CoQ)`,`Cytochrome a3`,`Molecular oxygen`], ans:1, exp:`Complex I oxidizes NADH and reduces ubiquinone (CoQ → CoQH2), simultaneously pumping 4H+ across the inner mitochondrial membrane. CoQ then shuttles electrons to Complex III.` },
      { q:`The modern P/O ratio for NADH oxidation (ATP per 2 electrons) is approximately:`, ch:[`1.0`,`1.5`,`2.0`,`2.5`], ans:3, exp:`Modern experimental measurements give P/O ratios of ~2.5 for NADH and ~1.5 for FADH2 (replacing older textbook values of 3 and 2). These reflect actual ATP synthase stoichiometry and proton pump H+ counts.` },
      { q:`Complex III (cytochrome bc1) transfers electrons from:`, ch:[`NADH to cytochrome c`,`CoQH2 to cytochrome c`,`Cytochrome c to O2`,`Succinate to CoQ`], ans:1, exp:`Complex III accepts electrons from ubiquinol (CoQH2) and transfers them to cytochrome c via the Q cycle, pumping 4H+ across the inner membrane per 2 electrons transferred.` },
      { q:`ATP synthase (Complex V) synthesizes ATP by:`, ch:[`Direct substrate-level phosphorylation`,`Using proton flow to drive rotational catalysis`,`Accepting electrons from cytochrome c`,`Oxidizing FADH2`], ans:1, exp:`ATP synthase uses the electrochemical proton gradient (chemiosmosis). H+ flow through the Fo subunit drives rotation of the gamma subunit, inducing conformational changes in F1 beta subunits that catalyze ATP synthesis.` },
      { q:`Cyanide poisoning kills by:`, ch:[`Inhibiting Complex I`,`Inhibiting cytochrome c oxidase (Complex IV), blocking O2 reduction`,`Uncoupling oxidative phosphorylation`,`Inhibiting ATP synthase directly`], ans:1, exp:`CN- binds to Fe3+ in cytochrome a3 of Complex IV, blocking electron transfer to O2. The entire ETC backs up, NADH accumulates, and ATP production halts — causing rapid cellular energy failure.` },
      { q:`UCP-1 (thermogenin) in brown adipose tissue allows protons to:`, ch:[`Enter the mitochondrial matrix via ATP synthase, boosting ATP`,`Leak across the inner mitochondrial membrane, dissipating energy as heat`,`Be exported from the matrix`,`Enter the intermembrane space from the matrix`], ans:1, exp:`UCP-1 is a proton transporter that bypasses ATP synthase, dissipating the proton gradient as heat (thermogenesis). Essential for non-shivering thermogenesis in newborns and cold-adapted mammals.` },
      { q:`Fluorocitrate (from fluoroacetate) blocks the TCA cycle by inhibiting:`, ch:[`Citrate synthase`,`Aconitase`,`Succinate dehydrogenase`,`Malate dehydrogenase`], ans:1, exp:`Fluoroacetate is converted to fluorocitrate, a potent inhibitor of aconitase (citrate → isocitrate). This causes citrate accumulation and halts the TCA cycle, making fluoroacetate highly toxic.` },
      { q:`Pyruvate carboxylase is an anaplerotic enzyme that:`, ch:[`Converts pyruvate to acetyl-CoA`,`Converts pyruvate to oxaloacetate, replenishing TCA intermediates`,`Converts OAA to PEP for gluconeogenesis`,`Decarboxylates pyruvate to acetaldehyde`], ans:1, exp:`Pyruvate carboxylase (biotin-dependent) converts pyruvate + CO2 → oxaloacetate, replenishing OAA consumed when amino acids exit the TCA cycle. It is activated by acetyl-CoA, linking TCA capacity to substrate availability.` },
      { q:`Succinate dehydrogenase is unique among TCA enzymes because it:`, ch:[`Uses NAD+ as electron acceptor`,`Is directly embedded in the inner mitochondrial membrane and doubles as Complex II`,`Produces CO2 as a product`,`Requires CoA as a cofactor`], ans:1, exp:`Succinate dehydrogenase is both a TCA enzyme and ETC Complex II. It is the only TCA enzyme embedded in the inner mitochondrial membrane. It uses FAD (not NAD+) as electron acceptor, directly feeding electrons into ubiquinone.` },
    ]
  },
  {
    id:'bb04', cat:'Bio/Biochem', title:'Molecular Biology & Genetics', diff:'Hard',
    qs:[
      { q:`Which enzyme synthesizes RNA from a DNA template during transcription?`, ch:[`DNA polymerase III`,`RNA polymerase`,`Reverse transcriptase`,`Primase`], ans:1, exp:`RNA polymerase reads the template strand (3'→5') and synthesizes RNA in the 5'→3' direction. In prokaryotes, a single RNA polymerase handles all RNA synthesis; eukaryotes have RNA pol I (rRNA), II (mRNA), and III (tRNA, 5S rRNA).` },
      { q:`The lac operon is induced when:`, ch:[`Glucose is abundant and lactose is absent`,`Lactose is present and glucose is absent`,`Only glucose is present`,`Neither glucose nor lactose is present`], ans:1, exp:`The lac operon is maximally induced when lactose is present (allolactose relieves repressor binding) and glucose is absent (cAMP-CAP activator is active). This demonstrates catabolite repression.` },
      { q:`Okazaki fragments are synthesized on the:`, ch:[`Leading strand in the 3'→5' direction`,`Lagging strand in the 5'→3' direction`,`Both strands simultaneously`,`Template strand by DNA polymerase I`], ans:1, exp:`The lagging strand is synthesized discontinuously in 5'→3' fragments (Okazaki fragments) because DNA polymerase can only add nucleotides to a 3'-OH. These fragments are later joined by DNA ligase.` },
      { q:`Which mutation type involves the insertion or deletion of a non-multiple-of-3 number of nucleotides?`, ch:[`Missense mutation`,`Nonsense mutation`,`Frameshift mutation`,`Silent mutation`], ans:2, exp:`A frameshift mutation shifts the reading frame, causing all downstream codons to be misread. Insertions or deletions of 1, 2, 4, or 5 nucleotides (any non-multiple of 3) cause frameshifts and typically produce truncated or nonfunctional proteins.` },
      { q:`The Shine-Dalgarno sequence in prokaryotes:`, ch:[`Codes for the start methionine`,`Is the promoter -10 sequence`,`Is an mRNA sequence that aligns the ribosome at the start codon`,`Is a termination signal for transcription`], ans:2, exp:`The Shine-Dalgarno sequence (~5-10 nt upstream of AUG) base-pairs with the 16S rRNA of the 30S subunit, positioning the ribosome for translation initiation. Eukaryotes use cap-dependent scanning instead.` },
      { q:`In eukaryotes, RNA processing includes all of the following EXCEPT:`, ch:[`5' cap addition`,`3' poly-A tail addition`,`Splicing of introns`,`Removal of Shine-Dalgarno sequence`], ans:3, exp:`Eukaryotic pre-mRNA processing includes 5' capping (7-methylguanosine), 3' polyadenylation, and splicing of introns by the spliceosome. The Shine-Dalgarno sequence is a prokaryotic ribosome-binding element, not present in eukaryotic mRNA.` },
      { q:`Which chromosome arrangement is described as XY trisomy (47,XXY)?`, ch:[`Turner syndrome`,`Klinefelter syndrome`,`Down syndrome`,`Patau syndrome`], ans:1, exp:`Klinefelter syndrome (47,XXY) is the most common sex chromosome aneuploidy in males (~1/600 male births). Features include tall stature, testicular atrophy, infertility, and gynecomastia. Caused by nondisjunction during meiosis.` },
      { q:`DNA replication is described as semiconservative because:`, ch:[`Each daughter DNA has one new and one original (parental) strand`,`Both strands of the parental DNA are completely degraded`,`Both new strands are synthesized simultaneously`,`Only one strand of the original DNA is used as a template`], ans:0, exp:`Meselson and Stahl (1958) demonstrated semiconservative replication using 15N/14N density labeling. Each daughter molecule retains one parental strand and gains one newly synthesized strand.` },
      { q:`The TATA box, found approximately 25-30 bp upstream of the transcription start site in eukaryotes, is:`, ch:[`A transcription termination signal`,`Part of the core promoter where TFIID (TBP) binds`,`An enhancer element`,`The polyadenylation signal`], ans:1, exp:`The TATA box is a core promoter element recognized by TFIID (specifically TBP, TATA-binding protein). Its binding positions RNA polymerase II for accurate transcription initiation. Not all eukaryotic promoters contain a TATA box.` },
      { q:`Genomic imprinting refers to:`, ch:[`Random X-chromosome inactivation in females`,`Gene expression dependent on the parent of origin due to epigenetic marks`,`Mutations caused by radiation`,`Homologous recombination during meiosis`], ans:1, exp:`Genomic imprinting is monoallelic gene expression based on parental origin. Imprinted genes are silenced by epigenetic marks (DNA methylation, histone modification) on one parental allele. Examples: IGF2 (paternal), H19 (maternal).` },
      { q:`Which DNA repair mechanism corrects thymine dimers caused by UV radiation?`, ch:[`Mismatch repair`,`Base excision repair`,`Nucleotide excision repair`,`Direct repair (photoreactivation)`], ans:2, exp:`Nucleotide excision repair (NER) removes bulky lesions like thymine dimers. ~25 nucleotides around the lesion are excised, then resynthesized by DNA polymerase. Defects in NER genes cause xeroderma pigmentosum.` },
      { q:`Alternative splicing is significant because it:`, ch:[`Allows one gene to produce multiple protein isoforms`,`Increases the mutation rate`,`Removes exons permanently from the genome`,`Only occurs in prokaryotes`], ans:0, exp:`Alternative splicing allows different exon combinations from a single pre-mRNA, generating protein isoforms with distinct functions. Humans have ~20,000 genes but can produce >100,000 distinct proteins largely through alternative splicing.` },
      { q:`A person with blood type AB has which genotype?`, ch:[`IAIA or IAi`,`IBIB or IBi`,`IAIB`,`ii`], ans:2, exp:`Blood type AB results from IAIB genotype — co-dominance of both A and B alleles. Type O = ii (recessive), Type A = IAIA or IAi, Type B = IBIB or IBi. The ABO locus demonstrates both co-dominance and multiple alleles.` },
      { q:`The polymerase chain reaction (PCR) requires all of the following EXCEPT:`, ch:[`Two oligonucleotide primers`,`Thermostable DNA polymerase (e.g., Taq)`,`dNTPs (deoxynucleotide triphosphates)`,`RNA polymerase and a promoter sequence`], ans:3, exp:`PCR amplifies DNA using: primers (flanking the target), Taq polymerase (heat-stable), dNTPs, and thermal cycling (denaturation, annealing, extension). RNA polymerase is not involved — PCR is a DNA amplification technique.` },
      { q:`Telomerase is necessary because:`, ch:[`It repairs double-strand DNA breaks`,`It extends the 5' end of newly synthesized strands, preventing end-replication shortening`,`It removes RNA primers from Okazaki fragments`,`It methylates cytosine residues in CpG islands`], ans:1, exp:`DNA polymerase cannot replicate the very 5' end of linear chromosomes (end-replication problem). Telomerase uses its own RNA template to add TTAGGG repeats to chromosome 3' ends, preventing progressive shortening with each division.` },
    ]
  },
  {
    id:'cp01', cat:'Chem/Phys', title:'Atomic Structure & Periodic Trends', diff:'Medium',
    qs:[
      { q:`The principal quantum number (n) determines:`, ch:[`Orbital shape`,`Orbital orientation in space`,`Energy level and average distance from nucleus`,`Electron spin state`], ans:2, exp:`n defines the shell (energy level) and correlates with distance from the nucleus. Higher n = higher energy, larger orbital, greater distance from nucleus. n can be 1, 2, 3...` },
      { q:`Moving across a period from left to right, atomic radius generally:`, ch:[`Increases`,`Decreases`,`Remains constant`,`First increases, then decreases`], ans:1, exp:`Atomic radius decreases left-to-right across a period because nuclear charge (Z) increases while electrons are added to the same shell, increasing effective nuclear charge (Zeff) and pulling electrons closer.` },
      { q:`Electronegativity is highest for which element?`, ch:[`Oxygen`,`Chlorine`,`Nitrogen`,`Fluorine`], ans:3, exp:`Fluorine (EN = 4.0 on Pauling scale) is the most electronegative element. Electronegativity increases up and to the right on the periodic table. O (3.5) and Cl (3.2) are next most electronegative.` },
      { q:`The first ionization energy of Na is much lower than that of Ne because:`, ch:[`Na has fewer total electrons`,`Na has a 3s electron in a higher energy shell that is farther from the nucleus and more shielded`,`Na has fewer protons`,`Na has a lower nuclear charge`], ans:1, exp:`After achieving the noble gas configuration of Ne (n=2 shell), Na starts a new shell (3s). This electron is farther from the nucleus and shielded by 10 inner electrons, requiring much less energy to remove.` },
      { q:`How many electrons can a d subshell hold?`, ch:[`2`,`6`,`10`,`14`], ans:2, exp:`d subshells have 5 orbitals (ml = -2, -1, 0, +1, +2), each holding 2 electrons, for a maximum of 10 electrons. (s=2, p=6, d=10, f=14)` },
      { q:`For Fe2+ (Fe ground state is [Ar]3d64s2), the correct electron configuration is:`, ch:[`[Ar]3d4`,`[Ar]3d6`,`[Ar]3d44s2`,`[Ar]3d8`], ans:1, exp:`Transition metals lose 4s electrons before 3d electrons when forming cations. Fe2+ loses both 4s electrons: [Ar]3d64s2 → [Ar]3d6. This produces the paramagnetic Fe2+ with 4 unpaired 3d electrons.` },
      { q:`Hund's rule states that electrons in degenerate orbitals:`, ch:[`Pair up in one orbital before occupying others`,`Occupy orbitals singly with parallel spins before pairing`,`Always have antiparallel spins`,`Fill the lowest energy orbital first`], ans:1, exp:`Hund's rule of maximum multiplicity: electrons occupy all degenerate orbitals singly with parallel spins before any pairing occurs. This minimizes electron-electron repulsion and gives the lowest energy configuration.` },
      { q:`Effective nuclear charge (Zeff) experienced by the valence electrons of Na is approximately:`, ch:[`11`,`8`,`2.5`,`1`], ans:2, exp:`Zeff = Z - S. For Na (Z=11): Slater's rules give shielding S ≈ 8.5 from the 10 inner electrons, so Zeff ≈ 11 - 8.5 = 2.51. The outer 3s electron does not fully experience all 11 nuclear protons due to shielding.` },
      { q:`Which of the following has the largest ionic radius?`, ch:[`Na+`,`Mg2+`,`F-`,`O2-`], ans:3, exp:`O2- has the largest ionic radius among these. All four are isoelectronic (10 electrons), but O2- has only 8 protons pulling those 10 electrons, giving the lowest Zeff and thus the largest radius. More protons = smaller radius for isoelectronic ions.` },
      { q:`The quantum number ml describes:`, ch:[`Energy level of the orbital`,`Shape of the orbital`,`Orientation of the orbital in space`,`Spin of the electron`], ans:2, exp:`ml (magnetic quantum number) specifies orbital orientation in a magnetic field. For l=1 (p orbitals): ml = -1, 0, +1, giving px, py, pz. For l=2 (d): ml = -2,-1,0,+1,+2, giving 5 d orbitals.` },
      { q:`Paramagnetic substances are best characterized by:`, ch:[`Having all paired electrons`,`Having one or more unpaired electrons`,`Being repelled by magnetic fields`,`Being noble gases`], ans:1, exp:`Paramagnetic substances contain one or more unpaired electrons and are attracted to external magnetic fields. Diamagnetic substances have all paired electrons and are weakly repelled. Fe3+ (5 unpaired 3d electrons) is strongly paramagnetic.` },
      { q:`Moving down a group on the periodic table, ionization energy generally:`, ch:[`Increases`,`Decreases`,`Remains the same`,`Alternates high and low`], ans:1, exp:`Ionization energy decreases down a group because valence electrons are in higher energy shells farther from the nucleus (more shielding from inner electrons), requiring less energy to remove despite increasing nuclear charge.` },
      { q:`The Aufbau principle states that electrons:`, ch:[`Fill higher energy orbitals before lower energy orbitals`,`Fill orbitals singly before pairing`,`Fill orbitals in order of increasing energy (lowest first)`,`Occupy any available orbital with parallel spin`], ans:2, exp:`The Aufbau principle (German: "building up") requires electrons to fill the lowest available energy orbitals first. The approximate filling order is: 1s, 2s, 2p, 3s, 3p, 4s, 3d, 4p, 5s, 4d, 5p...` },
      { q:`Which bond is MOST polar?`, ch:[`C-H`,`N-H`,`O-H`,`F-H`], ans:3, exp:`Bond polarity depends on electronegativity difference. F (EN=4.0) has the greatest difference with H (EN=2.1): ΔEN = 1.9. O-H: ΔEN=1.4; N-H: ΔEN=0.9; C-H: ΔEN=0.4. Greater difference = greater dipole moment.` },
      { q:`The de Broglie wavelength of a particle is inversely proportional to its:`, ch:[`Charge`,`Momentum (mass × velocity)`,`Temperature`,`Potential energy`], ans:1, exp:`de Broglie: λ = h/p = h/(mv). A heavier or faster-moving particle has a shorter wavelength. This wave-particle duality is significant for electrons (small mass) but negligible for macroscopic objects.` },
    ]
  },
  {
    id:'cp02', cat:'Chem/Phys', title:'Thermodynamics & Chemical Equilibrium', diff:'Hard',
    qs:[
      { q:`Gibbs free energy (ΔG) is defined as:`, ch:[`ΔH - TΔS`,`ΔH + TΔS`,`ΔS - TΔH`,`TΔS - ΔH`], ans:0, exp:`ΔG = ΔH - TΔS. A spontaneous reaction at constant T and P has ΔG < 0. The equation combines enthalpy (heat) and entropy contributions, weighted by temperature.` },
      { q:`A reaction with ΔH < 0 and ΔS < 0 is spontaneous:`, ch:[`At all temperatures`,`At high temperatures only`,`At low temperatures only`,`Never`], ans:2, exp:`When ΔH < 0 (exothermic) and ΔS < 0 (entropy decreases), ΔG = ΔH - TΔS < 0 only when |ΔH| > T|ΔS|, i.e., at low temperatures. At high T, the -TΔS term dominates and ΔG becomes positive (non-spontaneous).` },
      { q:`At equilibrium, ΔG equals:`, ch:[`ΔG° (standard free energy)`,`Zero`,`RT ln Keq`,`-RT ln Keq`], ans:1, exp:`At equilibrium, the forward and reverse reaction rates are equal and the free energy change for an additional increment of reaction is zero (ΔG = 0). This defines the equilibrium condition.` },
      { q:`The relationship between ΔG° and the equilibrium constant Keq is:`, ch:[`ΔG° = RT ln Keq`,`ΔG° = -RT ln Keq`,`ΔG° = Keq/RT`,`ΔG° = -Keq × RT`], ans:1, exp:`ΔG° = -RT ln Keq. If Keq > 1, ΔG° < 0 (products favored). If Keq < 1, ΔG° > 0 (reactants favored). At 37°C (310K), each 10-fold change in Keq corresponds to ~5.9 kJ/mol change in ΔG°.` },
      { q:`Le Chatelier's principle states that when a system at equilibrium is disturbed:`, ch:[`The equilibrium constant Keq changes`,`The system shifts to oppose the disturbance and restore equilibrium`,`Temperature always increases`,`The reaction stops until conditions are restored`], ans:1, exp:`Le Chatelier's principle: a system at equilibrium shifts to minimize the effect of any imposed change (adding product, changing pressure, changing temperature). Note: Keq only changes with temperature.` },
      { q:`For the reaction N2(g) + 3H2(g) ⇌ 2NH3(g), increasing pressure at constant temperature:`, ch:[`Shifts equilibrium toward N2 and H2 (left)`,`Shifts equilibrium toward NH3 (right)`,`Has no effect because Keq is constant`,`Increases Keq`], ans:1, exp:`Increasing pressure shifts the equilibrium toward the side with fewer moles of gas. The left side has 4 moles of gas (1 + 3); the right has 2. Higher pressure favors NH3 production (the Haber process).` },
      { q:`The entropy change (ΔS) is expected to be positive for:`, ch:[`Freezing of water`,`Formation of a solid from two gases`,`Dissolution of NaCl in water`,`Protein folding`], ans:2, exp:`Dissolving NaCl increases entropy: the ordered crystal lattice breaks down and ions become solvated in a disordered aqueous solution. The increase in disorder of ions in solution outweighs the slight ordering of water molecules.` },
      { q:`Hess's Law states that:`, ch:[`The enthalpy of a reaction depends on the path taken`,`The enthalpy of a reaction is the sum of enthalpies of intermediate steps, regardless of path`,`Entropy always increases in chemical reactions`,`Bond enthalpies are always endothermic`], ans:1, exp:`Hess's Law: enthalpy is a state function, so the total ΔH for a reaction equals the sum of ΔH for any series of steps connecting reactants to products, regardless of the actual mechanism.` },
      { q:`The reaction quotient Q is used to predict equilibrium shift. If Q < Keq:`, ch:[`The reaction will shift to the left (toward reactants)`,`The reaction will shift to the right (toward products)`,`The system is already at equilibrium`,`Keq must increase to reach equilibrium`], ans:1, exp:`When Q < Keq, the numerator (products) is too small relative to equilibrium — the reaction must proceed forward (right) to produce more products and reach equilibrium. If Q > Keq, the reaction shifts left.` },
      { q:`Which thermodynamic quantity is a measure of the dispersal of energy or matter?`, ch:[`Enthalpy (H)`,`Gibbs free energy (G)`,`Entropy (S)`,`Internal energy (U)`], ans:2, exp:`Entropy (S) quantifies the disorder or dispersal of energy and matter among microstates. The Second Law of Thermodynamics states that the total entropy of the universe always increases for spontaneous processes.` },
      { q:`A catalyst increases reaction rate by:`, ch:[`Increasing ΔG° for the reaction`,`Lowering the activation energy (Ea)`,`Increasing the temperature`,`Shifting the equilibrium toward products`], ans:1, exp:`Catalysts lower the activation energy by providing an alternative reaction mechanism with a lower-energy transition state. They increase both forward and reverse rates equally, so they do not change Keq or ΔG°.` },
      { q:`For an endothermic reaction, increasing temperature:`, ch:[`Decreases Keq`,`Increases Keq`,`Has no effect on Keq`,`Decreases the rate of the forward reaction`], ans:1, exp:`For endothermic reactions (ΔH > 0), heat is a reactant. Increasing temperature shifts equilibrium right, increasing Keq. The van't Hoff equation: d(ln Keq)/dT = ΔH°/RT2. This is why equilibrium constants change with temperature.` },
      { q:`The second law of thermodynamics states that:`, ch:[`Energy is conserved in all processes`,`The entropy of the universe increases for all spontaneous processes`,`Heat flows from cold to hot objects`,`All reactions proceed toward minimum energy`], ans:1, exp:`The Second Law: total entropy of the universe (system + surroundings) always increases for spontaneous (irreversible) processes: ΔSuniverse > 0. This determines the direction of spontaneous change.` },
      { q:`A process with ΔG > 0 is:`, ch:[`Spontaneous`,`Non-spontaneous (requires energy input)`,`At equilibrium`,`Always endothermic`], ans:1, exp:`ΔG > 0 indicates a non-spontaneous process under the given conditions. To drive it forward, energy must be supplied (e.g., coupled to ATP hydrolysis in biological systems, where ΔG° = -30.5 kJ/mol).` },
      { q:`The standard enthalpy of formation (ΔHf°) of any pure element in its standard state is:`, ch:[`+100 kJ/mol`,`Dependent on temperature`,`Zero by definition`,`Equal to its ionization energy`], ans:2, exp:`By convention, ΔHf° = 0 for all elements in their standard states (e.g., O2(g), C(graphite), H2(g)). This reference point allows calculation of ΔH° for any reaction from tabulated ΔHf° values using Hess's Law.` },
    ]
  },
  {
    id:'cp03', cat:'Chem/Phys', title:'Fluids, Circuits & Optics', diff:'Hard',
    qs:[
      { q:`Bernoulli's equation relates fluid speed to pressure. As fluid speed increases in a constricted tube:`, ch:[`Pressure increases`,`Pressure decreases`,`Pressure stays constant`,`Density increases`], ans:1, exp:`Bernoulli's principle: P + ½ρv² + ρgh = constant. In a constriction, velocity increases and pressure must decrease to conserve energy. This is why airplane wings generate lift and why arteries can bulge in aneurysms.` },
      { q:`The continuity equation (A1v1 = A2v2) for incompressible fluids states that:`, ch:[`Pressure is constant throughout`,`Flow rate (volume per time) is constant`,`Velocity is constant`,`Density changes with cross-section`], ans:1, exp:`The continuity equation expresses conservation of mass for incompressible fluids: A1v1 = A2v2, so fluid in a narrow region flows faster. This is why blood velocity is lowest in capillaries (large total cross-sectional area) despite low individual capillary radius.` },
      { q:`Ohm's Law states that current (I) equals:`, ch:[`Voltage (V) × Resistance (R)`,`Voltage (V) / Resistance (R)`,`Resistance (R) / Voltage (V)`,`Voltage (V) + Resistance (R)`], ans:1, exp:`Ohm's Law: I = V/R. Current is directly proportional to voltage and inversely proportional to resistance. At constant voltage, doubling resistance halves current. Units: V in volts, R in ohms (Ω), I in amperes (A).` },
      { q:`Resistors in series are combined by:`, ch:[`1/Rtotal = 1/R1 + 1/R2`,`Rtotal = R1 + R2`,`Rtotal = R1 × R2 / (R1 + R2)`,`Rtotal = R1 = R2`], ans:1, exp:`In series, the same current flows through all resistors and voltages add: Rtotal = R1 + R2 + ... Total resistance always increases when adding series resistors. Equivalent to longer wire.` },
      { q:`The power dissipated by a resistor can be expressed as:`, ch:[`P = IV = I²R = V²/R`,`P = IR`,`P = V/R`,`P = I/V`], ans:0, exp:`Power dissipation: P = IV = I²R = V²/R (all equivalent via Ohm's Law). A 100Ω resistor with 2A flowing through it dissipates P = I²R = 4 × 100 = 400W as heat.` },
      { q:`Snell's Law (n1 sin θ1 = n2 sin θ2) describes:`, ch:[`Reflection of light`,`Refraction at an interface between two media`,`Diffraction through a slit`,`Interference of light waves`], ans:1, exp:`Snell's Law describes how light bends at an interface. When light moves from a lower index medium to higher index (n2 > n1), it bends toward the normal (θ2 < θ1). Total internal reflection occurs when θ1 exceeds the critical angle.` },
      { q:`A converging (convex) lens with focal length f=20 cm and object distance do=60 cm will produce an image at di=:`, ch:[`10 cm`,`20 cm`,`30 cm`,`-60 cm`], ans:2, exp:`Thin lens equation: 1/f = 1/do + 1/di → 1/20 = 1/60 + 1/di → 1/di = 1/20 - 1/60 = 3/60 - 1/60 = 2/60 → di = 30 cm. A positive di means a real image on the opposite side from the object.` },
      { q:`Gauge pressure is defined as:`, ch:[`Pressure at sea level`,`Absolute pressure - atmospheric pressure`,`Pressure below vacuum`,`The pressure of an ideal gas`], ans:1, exp:`Gauge pressure = Absolute pressure - Patm. Gauge pressure is what most pressure gauges measure (e.g., tire pressure, blood pressure cuffs). Absolute pressure = gauge pressure + 101,325 Pa (1 atm).` },
      { q:`The index of refraction of a medium is defined as:`, ch:[`c/v (speed of light in vacuum / speed in medium)`,`v/c (speed in medium / speed in vacuum)`,`wavelength in vacuum / frequency`,`frequency × wavelength in medium`], ans:0, exp:`n = c/v, where c = 3×10⁸ m/s in vacuum and v is the speed of light in the medium. Water has n ≈ 1.33 (light travels at 0.75c in water). Higher n means light slows more and bends more at interfaces.` },
      { q:`Capacitors in parallel are combined by:`, ch:[`Ctotal = C1 × C2 / (C1+C2)`,`1/Ctotal = 1/C1 + 1/C2`,`Ctotal = C1 + C2`,`Ctotal = C1 = C2`], ans:2, exp:`Capacitors in parallel share the same voltage. Total capacitance adds: Ctotal = C1 + C2 + ... This is opposite to resistors. In parallel, adding capacitors increases total capacitance (think of larger total plate area).` },
      { q:`Viscosity of a fluid most directly affects:`, ch:[`Bernoulli equation validity`,`Poiseuille flow (resistance to flow in tubes)`,`Buoyancy force`,`Pascal's law`], ans:1, exp:`Poiseuille's law: Q = πr⁴ΔP / (8ηL). Flow rate is inversely proportional to viscosity (η). Blood viscosity (~3-4 cP) is a major factor in vascular resistance. Viscosity increases with hematocrit and decreases with temperature.` },
      { q:`Which phenomenon explains why a straw works when you suck liquid up?`, ch:[`Bernoulli's principle increases pressure at the top`,`Lowering pressure in the straw allows atmospheric pressure to push liquid up`,`Gravity is reversed inside the straw`,`Osmotic pressure draws fluid up`], ans:1, exp:`When you suck, you reduce air pressure above the liquid in the straw. Atmospheric pressure (101,325 Pa) acting on the liquid surface then pushes the liquid up. Maximum height possible with 1 atm pressure ≈ 10.3 m of water.` },
      { q:`An object submerged in fluid experiences a buoyant force equal to:`, ch:[`The mass of the object`,`The weight of fluid displaced by the object (Archimedes' principle)`,`The volume of the object × density of object`,`The surface area of the object × pressure`], ans:1, exp:`Archimedes' principle: buoyant force = weight of displaced fluid = ρfluid × V_displaced × g. Objects float when their average density < fluid density. An object of density 800 kg/m³ would float with 80% submerged in water (density 1000 kg/m³).` },
      { q:`In a simple circuit with an ideal battery (EMF = 12V) and two 4Ω resistors in series, the current is:`, ch:[`3 A`,`1.5 A`,`6 A`,`24 A`], ans:1, exp:`Rtotal = 4 + 4 = 8 Ω. I = V/R = 12/8 = 1.5 A. Voltage drops across each resistor: V = IR = 1.5 × 4 = 6V per resistor. The two 6V drops sum to 12V (matching the EMF), confirming Kirchhoff's voltage law.` },
      { q:`Total internal reflection occurs when:`, ch:[`Light moves from a higher to lower index medium at an angle greater than the critical angle`,`Light moves from a lower to higher index medium`,`The angle of incidence equals the angle of refraction`,`The wavelength matches the medium thickness`], ans:0, exp:`When light travels from a denser medium (higher n) to a less dense medium (lower n) at an angle exceeding the critical angle θc = sin⁻¹(n2/n1), all light reflects internally with no transmission. This is the basis of fiber optics.` },
    ]
  },
  {
    id:'cp04', cat:'Chem/Phys', title:'Organic Chemistry Reactions', diff:'Hard',
    qs:[
      { q:`In an SN2 reaction, the rate depends on:`, ch:[`Only substrate concentration`,`Only nucleophile concentration`,`Both substrate and nucleophile concentrations`,`Temperature only`], ans:2, exp:`SN2 is bimolecular: rate = k[substrate][nucleophile]. The nucleophile attacks in a concerted, backside mechanism causing inversion of configuration (Walden inversion). Primary substrates react fastest; tertiary substrates do not undergo SN2.` },
      { q:`An E2 elimination reaction is favored by:`, ch:[`Polar aprotic solvents and strong nucleophiles`,`Polar protic solvents and weak bases`,`Strong bulky bases and high temperature`,`Weak nucleophiles and tertiary substrates`], ans:2, exp:`E2 is favored by strong, bulky bases (e.g., tert-butoxide) and high temperature. The mechanism is concerted (anti-periplanar geometry required). Unlike SN2, bulky bases favor elimination over substitution at tertiary and secondary substrates.` },
      { q:`Markovnikov's rule predicts that in HX addition to an alkene, H adds to the carbon with:`, ch:[`More substituents`,`Fewer substituents (more hydrogens)`,`The higher electronegativity`,`The smaller atomic radius`], ans:1, exp:`Markovnikov's rule: H adds to the carbon bearing more H atoms (fewer substituents), forming the more stable carbocation intermediate at the more substituted carbon. This explains the regioselectivity of electrophilic addition.` },
      { q:`Which reagent converts a carboxylic acid to an ester?`, ch:[`NaOH/H2O`,`SOCl2`,`Alcohol + acid catalyst (Fischer esterification)`,`LiAlH4`], ans:2, exp:`Fischer esterification: RCOOH + R'OH ⇌ RCOOR' + H2O (acid catalyst, H2SO4 or HCl). The reaction is reversible; removing water drives it toward ester formation. SOCl2 forms acid chlorides; LiAlH4 reduces carboxylic acids to primary alcohols.` },
      { q:`The Diels-Alder reaction requires:`, ch:[`A nucleophile and electrophile`,`A conjugated diene (s-cis conformation) and a dienophile`,`Radical initiation`,`An organometallic catalyst`], ans:1, exp:`The Diels-Alder is a [4+2] cycloaddition between a conjugated diene (must be s-cis) and a dienophile (electron-poor alkene, e.g., containing C=O or CN groups). It forms 6-membered rings with excellent stereochemical control.` },
      { q:`Which compound is the most acidic?`, ch:[`Ethanol (pKa ~16)`,`Acetic acid (pKa ~4.75)`,`Phenol (pKa ~10)`,`Water (pKa ~15.7)`], ans:1, exp:`Acetic acid (pKa 4.75) is most acidic. The carboxylate anion is stabilized by resonance delocalization across both oxygens. Lower pKa = stronger acid. pKa order: acetic acid (4.75) < phenol (10) < water (15.7) < ethanol (16).` },
      { q:`Ozonolysis of a double bond followed by reductive workup (Me2S or Zn) produces:`, ch:[`Carboxylic acids`,`Epoxides`,`Aldehydes and/or ketones`,`Alkyl halides`], ans:2, exp:`Ozonolysis cleaves the C=C double bond. Reductive workup (Me2S or Zn/HOAc) gives aldehydes (from CH= end) or ketones (from R2C= end). Oxidative workup (H2O2) gives carboxylic acids instead of aldehydes.` },
      { q:`Which spectroscopic method best distinguishes an aldehyde from a ketone?`, ch:[`UV-Vis spectroscopy`,`Mass spectrometry alone`,`1H NMR (aldehyde H appears near δ 9-10 ppm)`,`Elemental analysis`], ans:2, exp:`In 1H NMR, aldehyde protons (CHO) appear as a singlet around δ 9-10 ppm — a distinctive low-field signal due to the deshielding effect of the adjacent carbonyl. IR shows C=O stretch around 1700-1740 cm-1 for both, but NMR distinguishes them.` },
      { q:`In an SN1 reaction, the carbocation intermediate leads to:`, ch:[`Complete inversion of configuration`,`Complete retention of configuration`,`Racemization (mixture of inversion and retention)`,`No stereocenters formed`], ans:2, exp:`The planar carbocation intermediate can be attacked by nucleophile from either face, producing a racemic mixture (or partial racemization if there is some steric preference). This loss of stereochemical integrity is a hallmark of SN1.` },
      { q:`Which functional group shows a broad O-H stretch around 3200-3500 cm-1 in IR spectroscopy?`, ch:[`Aldehyde`,`Amine`,`Alcohol or carboxylic acid`,`Alkyne`], ans:2, exp:`The O-H stretch appears as a broad peak at 3200-3500 cm-1 due to hydrogen bonding. Alcohols show this broad peak; carboxylic acids show an even broader O-H stretch extending to ~2500 cm-1. Alkynes show sharp C≡C and terminal ≡C-H stretches.` },
      { q:`Reduction of a ketone with NaBH4 produces:`, ch:[`A primary alcohol`,`A secondary alcohol`,`A carboxylic acid`,`An aldehyde`], ans:1, exp:`NaBH4 reduces ketones (R-CO-R') to secondary alcohols (R-CHOH-R'). LiAlH4 is a stronger reductant that reduces carboxylic acids, esters, and amides. Aldehydes give primary alcohols upon reduction.` },
      { q:`An aldol condensation between two acetaldehyde molecules produces:`, ch:[`Acetone`,`3-Hydroxybutanal (aldol product)`,`Butanedioic acid`,`Ethylene glycol`], ans:1, exp:`Aldol condensation: an alpha-carbon enolate attacks another carbonyl carbon, forming a beta-hydroxy carbonyl compound (aldol product). Dehydration gives the alpha,beta-unsaturated carbonyl (aldol condensation product). Key C-C bond forming reaction.` },
      { q:`The term 'R' configuration (Cahn-Ingold-Prelog) is assigned when substituent priority decreases in a __ rotation with the lowest priority group pointing away:`, ch:[`Counterclockwise`,`Clockwise`,`Either direction`,`Vertical`], ans:1, exp:`R (Latin rectus = right) is assigned when the sequence of substituents 1→2→3 (decreasing priority) traces a clockwise arc, with the lowest priority group (4) pointing away from you. S (sinister = left) is counterclockwise.` },
      { q:`Which reagent sequence converts an alkene to an anti-diol?`, ch:[`OsO4, then H2O2`,`mCPBA, then H2O/H+`,`Br2 in CCl4`,`H2, Pd/C`], ans:1, exp:`mCPBA forms an epoxide with syn addition, then acid-catalyzed ring opening of the epoxide by water attacks from the backside (anti), giving an anti-diol overall. OsO4 gives syn diols. Br2/CCl4 gives vicinal anti-dibromides.` },
      { q:`What does a triplet (t) signal in 1H NMR indicate?`, ch:[`Three equivalent protons on the observed carbon`,`Two neighboring protons on adjacent carbons`,`Three neighboring protons on adjacent carbons`,`A carbon with 3 hydrogens directly attached`], ans:1, exp:`By the n+1 rule, a triplet (3 lines) results from 2 neighboring (non-equivalent) protons on adjacent carbons. A CH3 group adjacent to a CH2 gives a triplet (for the CH3) and a quartet (for the CH2), the classic ethyl pattern.` },
    ]
  },
  {
    id:'cp05', cat:'Chem/Phys', title:'Acid-Base Chemistry & Electrochemistry', diff:'Hard',
    qs:[
      { q:`According to the Brønsted-Lowry definition, an acid is:`, ch:[`An electron pair donor`,`A proton (H+) donor`,`A proton (H+) acceptor`,`An electron pair acceptor`], ans:1, exp:`Brønsted-Lowry: acids donate protons (H+); bases accept protons. This extends beyond Arrhenius (H+ in water) to any proton-transfer reaction. Lewis definition is broader still: acid = electron pair acceptor.` },
      { q:`The Henderson-Hasselbalch equation is:`, ch:[`pH = pKa × [A-]/[HA]`,`pH = pKa + log([A-]/[HA])`,`pH = pKa - log([HA]/[A-])`,`pH = Ka + log([H+])`], ans:1, exp:`Henderson-Hasselbalch: pH = pKa + log([conjugate base]/[acid]). At pH = pKa, [A-] = [HA] (50/50 ratio). Effective buffering range is approximately pKa ± 1 pH unit.` },
      { q:`A buffer is most effective at resisting pH change when:`, ch:[`pH is far from pKa`,`pH equals pKa (equal concentrations of acid and conjugate base)`,`The acid concentration is much greater than the base`,`The solution is very dilute`], ans:1, exp:`Maximum buffering capacity occurs when [HA] = [A-], i.e., pH = pKa. At this point, the buffer can absorb equal amounts of added acid or base. Practical buffering range: pKa ± 1.` },
      { q:`The autoionization constant of water (Kw) at 25°C equals:`, ch:[`1.0 × 10-7`,`1.0 × 10-14`,`1.0 × 10-7 × 10-7`,`7.0`], ans:1, exp:`Kw = [H+][OH-] = 1.0 × 10-14 at 25°C. In pure water, [H+] = [OH-] = 1.0 × 10-7 M, giving pH = 7 (neutral). Kw increases with temperature (autoionization is endothermic), so neutral pH decreases with increasing temperature.` },
      { q:`In a galvanic (voltaic) cell, oxidation occurs at the:`, ch:[`Cathode`,`Anode`,`Salt bridge`,`External circuit`], ans:1, exp:`In all electrochemical cells (galvanic and electrolytic): oxidation occurs at the anode, reduction at the cathode. Mnemonic: "AN OX RED CAT" (ANode = OXidation; REDuction = CAThode). Galvanic cells have a negative anode; electrolytic cells have a positive anode.` },
      { q:`The standard cell potential E°cell is calculated as:`, ch:[`E°cathode - E°anode (reduction potentials)`,`E°anode - E°cathode`,`E°cathode + E°anode`,`E°cathode × E°anode`], ans:0, exp:`E°cell = E°cathode - E°anode (both as standard reduction potentials). A positive E°cell means the reaction is spontaneous (ΔG° < 0). E°cell is related to ΔG° by: ΔG° = -nFE°cell.` },
      { q:`What is the pH of a 0.01 M HCl solution?`, ch:[`1`,`2`,`7`,`13`], ans:1, exp:`HCl is a strong acid, fully dissociated: [H+] = 0.01 M = 10-2 M. pH = -log[H+] = -log(10-2) = 2. For strong acids, simply take -log of the concentration.` },
      { q:`Weak acids differ from strong acids in that weak acids:`, ch:[`Have higher molecular weight`,`Only partially dissociate in water (Ka << 1)`,`Cannot be titrated`,`Do not donate protons`], ans:1, exp:`Weak acids (e.g., acetic acid, Ka = 1.8 × 10-5) only partially ionize in water. At equilibrium, most molecules remain as HA. Strong acids (HCl, HNO3, H2SO4, etc.) dissociate essentially completely (Ka >> 1).` },
      { q:`At the equivalence point of a strong acid-weak base titration, the solution is:`, ch:[`Neutral (pH = 7)`,`Acidic (pH < 7)`,`Basic (pH > 7)`,`At the pKa of the weak base`], ans:1, exp:`At the equivalence point, all base is converted to its conjugate acid (NH4+ if the base was NH3). This conjugate acid hydrolyzes water to give H+, making the solution acidic. Strong acid + strong base = neutral equivalence point.` },
      { q:`The Nernst equation relates cell potential to:`, ch:[`Temperature only`,`Concentration of reactants and products (reaction quotient Q)`,`The number of moles of reactants`,`Electrode surface area`], ans:1, exp:`Nernst equation: E = E° - (RT/nF)ln Q. At 25°C: E = E° - (0.0592/n)log Q. Non-standard concentrations reduce (or increase) cell potential from E°cell. At equilibrium, E = 0 and Q = Keq.` },
      { q:`Which of the following is a polyprotic acid?`, ch:[`HCl`,`HNO3`,`H3PO4`,`CH3COOH`], ans:2, exp:`H3PO4 (phosphoric acid) is triprotic — it can donate 3 protons sequentially (pKa1=2.1, pKa2=7.2, pKa3=12.4). These stepwise pKas are important in biological pH buffering. HCl, HNO3 are monoprotic strong acids.` },
      { q:`A solution with pH 11 has [OH-] equal to:`, ch:[`10-11 M`,`10-3 M`,`10-2 M`,`10-1 M`], ans:1, exp:`pOH = 14 - pH = 14 - 11 = 3. [OH-] = 10-pOH = 10-3 M. Alternatively: [H+] = 10-11 M, and [OH-] = Kw/[H+] = 10-14/10-11 = 10-3 M.` },
      { q:`In electrolysis, the minimum voltage required to decompose a compound is related to:`, ch:[`The mass of electrodes`,`The temperature of the solution`,`The standard cell potential (E°cell)`,`The current density alone`], ans:2, exp:`The minimum decomposition voltage equals the standard cell potential E°cell for the reverse (non-spontaneous) reaction. In practice, additional overpotential is required due to electrode kinetics. Energy input = voltage × charge = -ΔG.` },
      { q:`Which salt hydrolyzes to give a basic solution?`, ch:[`NaCl`,`NH4Cl`,`Na2CO3`,`NaHSO4`], ans:2, exp:`Na2CO3 is the salt of a strong base (NaOH) and a weak acid (H2CO3). The carbonate ion (CO32-) hydrolyzes water: CO32- + H2O ⇌ HCO3- + OH-, making the solution basic. NH4Cl is acidic; NaCl is neutral; NaHSO4 is acidic.` },
      { q:`A species that can act as both an acid and a base is called:`, ch:[`Neutral`,`Amphoteric`,`Amphiphilic`,`Zwitterionic`], ans:1, exp:`Amphoteric species can both donate and accept protons. Water is amphoteric (acid: H2O → H+ + OH-; base: H2O + H+ → H3O+). Amino acids are amphoteric. HCO3- is amphoteric: it can donate H+ (acid) or accept H+ (base).` },
    ]
  },
  {
    id:'ps01', cat:'Psych/Soc', title:'Social Psychology & Cognition', diff:'Medium',
    qs:[
      { q:`The fundamental attribution error refers to the tendency to:`, ch:[`Attribute our own failures to situational factors`,`Overestimate dispositional factors and underestimate situational factors when explaining others' behavior`,`Attribute our own successes to personal qualities`,`Overestimate situational factors for others' behavior`], ans:1, exp:`The fundamental attribution error: when explaining others' behavior, people over-rely on internal/dispositional factors (personality) and underestimate situational factors. We are more aware of situational pressures when evaluating our own behavior.` },
      { q:`Cognitive dissonance occurs when:`, ch:[`Two people have conflicting opinions`,`A person holds conflicting beliefs or behaves contrary to their beliefs`,`A person cannot remember past events`,`A stimulus produces two different perceptions`], ans:1, exp:`Cognitive dissonance (Festinger, 1957): psychological discomfort from holding contradictory cognitions or when actions conflict with beliefs. Motivation to reduce dissonance drives attitude change, rationalization, or behavior modification.` },
      { q:`Conformity in Asch's line experiments was driven primarily by:`, ch:[`Informational influence (uncertainty about correct answer)`,`Normative social influence (desire to fit in and avoid rejection)`,`Obedience to authority`,`Groupthink`], ans:1, exp:`Asch's conformity studies showed participants giving obviously wrong answers to conform to group responses. This was primarily normative influence (social pressure), not informational — participants knew the group was wrong but conformed anyway.` },
      { q:`In Milgram's obedience studies, the level of obedience to authority was:`, ch:[`Very low (most refused to administer shocks)`,`Moderate (~50% compliance)`,`Surprisingly high (~65% complied to 450V)`,`Complete (100% compliance)`], ans:2, exp:`Milgram found ~65% of participants administered what they believed to be 450V shocks when ordered by an authority figure. The studies revealed the power of authority and situational pressures to override personal conscience.` },
      { q:`Social loafing refers to:`, ch:[`Improved performance when working with others`,`Reduced individual effort when working in a group`,`Hostility between groups`,`Prejudice against social minorities`], ans:1, exp:`Social loafing: individuals exert less effort in group tasks than alone, especially when individual contributions cannot be easily identified or evaluated. Effect is reduced when contributions are identifiable or the task is meaningful.` },
      { q:`The bystander effect occurs because of:`, ch:[`Diffusion of responsibility and pluralistic ignorance`,`Group cohesion and social identity`,`Authority compliance`,`Conformity to social norms`], ans:0, exp:`The bystander effect (Latané and Darley): each person in a group feels less personally responsible (diffusion of responsibility) and assumes others will act. Pluralistic ignorance — each person assumes others are not concerned, so follows their inaction.` },
      { q:`Self-serving bias describes the tendency to:`, ch:[`Attribute successes to internal factors and failures to external factors`,`Attribute both successes and failures to external factors`,`Attribute both successes and failures to internal factors`,`Always blame others for negative outcomes`], ans:0, exp:`Self-serving bias: we credit our successes to internal factors (skill, intelligence) but attribute failures to external factors (bad luck, difficult circumstances). This protects self-esteem and is the opposite of how we evaluate others (fundamental attribution error).` },
      { q:`Groupthink is most likely to occur when:`, ch:[`Group members have diverse opinions`,`The group has a strong leader and high cohesion with pressure for conformity`,`The group has no leader`,`Decision is not time-pressured`], ans:1, exp:`Groupthink (Janis, 1972): deterioration of rational decision-making in highly cohesive groups under pressure. Symptoms include illusion of invulnerability, collective rationalization, stereotyping of outgroups, self-censorship, and illusion of unanimity.` },
      { q:`Prejudice is best defined as:`, ch:[`A behavior directed against a group`,`A negative attitude or prejudgment toward members of a group`,`A belief that one group is superior`,`A social norm that excludes minorities`], ans:1, exp:`Prejudice is an attitude (often negative) toward members of a group based solely on their membership. Discrimination is the behavioral expression of prejudice. Stereotypes are cognitive generalizations about groups.` },
      { q:`The halo effect refers to:`, ch:[`A judgment error where knowing one positive trait influences perception of all other traits`,`The tendency to conform to group norms`,`Improved recall under emotional arousal`,`A bias in face perception`], ans:0, exp:`The halo effect: a cognitive bias where one positive trait (e.g., physical attractiveness) influences overall perception of other unrelated traits (intelligence, competence, honesty). The "devil effect" is the reverse — one negative trait colors all perceptions.` },
      { q:`Schemas in cognitive psychology are:`, ch:[`Reflexive behaviors`,`Mental frameworks that organize and interpret information`,`Emotional responses to stimuli`,`Long-term memories of specific events`], ans:1, exp:`Schemas are cognitive structures or frameworks that help us organize and interpret information efficiently. They allow rapid processing but can cause confirmation bias (interpreting new information to fit existing schemas) and stereotyping.` },
      { q:`The elaboration likelihood model (ELM) describes:`, ch:[`How emotions affect memory`,`Two routes to attitude change: central (thoughtful) and peripheral (surface cues)`,`How schemas form`,`Social comparison processes`], ans:1, exp:`ELM (Petty and Cacioppo): central route = attitude change through careful analysis of arguments (durable change); peripheral route = attitude change through heuristic cues like source attractiveness or credibility (less durable). Route depends on motivation and ability.` },
      { q:`Social facilitation theory predicts that the presence of others:`, ch:[`Always improves performance`,`Improves performance on well-learned tasks but impairs performance on novel/difficult tasks`,`Always impairs performance`,`Has no effect on performance`], ans:1, exp:`Zajonc's social facilitation: the presence of others increases arousal, which enhances performance on dominant (well-learned) responses but impairs performance on non-dominant (novel or complex) responses. Explains why audiences help experts but hurt beginners.` },
      { q:`The mere exposure effect states that:`, ch:[`Familiarity with a stimulus decreases liking`,`Repeated exposure to a stimulus increases liking for it`,`Complex stimuli are preferred over simple ones`,`Exposure to persuasion increases resistance`], ans:1, exp:`The mere exposure effect (Zajonc): simple repeated exposure to a stimulus is sufficient to increase positive affect toward it, even without any direct reinforcement. This is one reason familiar brands, faces, and music are preferred.` },
      { q:`Stereotype threat occurs when:`, ch:[`A person behaves according to a positive stereotype`,`Awareness of a negative stereotype about one's group impairs performance`,`A person is unaware of stereotypes about their group`,`Positive stereotypes improve self-concept`], ans:1, exp:`Stereotype threat (Steele and Aronson): when individuals are aware of a negative stereotype about their group, the apprehension about confirming that stereotype impairs performance in that domain. It is an additional cognitive/emotional burden during task performance.` },
    ]
  },
  {
    id:'ps02', cat:'Psych/Soc', title:'Development, Learning & Memory', diff:'Medium',
    qs:[
      { q:`Piaget's concrete operational stage (ages ~7-12) is characterized by:`, ch:[`Object permanence and stranger anxiety`,`Logical thinking about concrete objects, conservation, and reversibility`,`Abstract and hypothetical reasoning`,`Egocentric thinking and animism`], ans:1, exp:`Concrete operations: children develop logical thinking about physical/concrete objects, understand conservation (e.g., volume is conserved when liquid is poured into different shaped containers), seriation, and classification. They still struggle with abstract reasoning.` },
      { q:`In classical conditioning, extinction occurs when:`, ch:[`The CS is paired with a stronger US`,`The CS is repeatedly presented without the US, weakening the conditioned response`,`A new CS is introduced`,`The response generalizes to similar stimuli`], ans:1, exp:`Extinction: repeatedly presenting the conditioned stimulus (CS) without the unconditioned stimulus (US) weakens and eventually eliminates the conditioned response (CR). The association is not erased but is suppressed — it can spontaneously recover.` },
      { q:`Operant conditioning differs from classical conditioning in that operant conditioning involves:`, ch:[`Pairing a neutral stimulus with an unconditioned stimulus`,`Learning through consequences (reinforcement and punishment) of voluntary behaviors`,`Involuntary reflex responses`,`Biological preparedness only`], ans:1, exp:`Operant conditioning (Skinner): behavior is shaped by its consequences. Reinforcement (positive/negative) increases behavior frequency; punishment decreases it. Unlike classical conditioning (involuntary reflexes), operant conditioning involves voluntary behaviors.` },
      { q:`Negative reinforcement is:`, ch:[`Punishment`,`Adding something aversive to decrease a behavior`,`Removing something aversive to increase a behavior`,`Removing something pleasant to decrease a behavior`], ans:2, exp:`Negative reinforcement: removing an aversive stimulus following a behavior INCREASES that behavior. Example: taking ibuprofen (behavior) removes headache pain (aversive stimulus) — you are negatively reinforced to take ibuprofen again. Not punishment. "Negative" refers to removal, not unpleasantness.` },
      { q:`Erikson's psychosocial stage for adolescence (12-18 years) is:`, ch:[`Industry vs. Inferiority`,`Identity vs. Role Confusion`,`Intimacy vs. Isolation`,`Initiative vs. Guilt`], ans:1, exp:`Erikson's stage for adolescence: Identity vs. Role Confusion. Adolescents explore who they are (values, beliefs, roles). Successful resolution leads to a coherent identity; failure leads to confusion about self and one's place in society.` },
      { q:`The spacing effect (distributed practice) in memory refers to:`, ch:[`Massed practice (cramming) is superior for long-term retention`,`Information studied over multiple spaced sessions is better retained long-term`,`All study sessions should be equally long`,`Memory is unaffected by timing of practice`], ans:1, exp:`Distributed practice (spacing effect): studying in spaced-out sessions produces better long-term retention than equivalent massed practice (cramming). Each retrieval attempt strengthens memory. Recommended for all types of learning.` },
      { q:`The misinformation effect demonstrated by Loftus shows that:`, ch:[`Eyewitness memory is highly accurate`,`Leading questions or post-event information can alter memory for past events`,`False memories cannot be implanted`,`Memory is photographic`], ans:1, exp:`Loftus's research showed that post-event misinformation (leading questions, suggestive descriptions) can alter memories of witnessed events. Eyewitness testimony is susceptible to suggestion, raising concerns about its reliability in legal settings.` },
      { q:`Working memory (short-term memory) has a capacity of approximately:`, ch:[`1-3 items`,`7 ± 2 items (Miller's law)`,`20+ items`,`Unlimited with rehearsal`], ans:1, exp:`Miller's law (1956): working memory capacity is approximately 7 ± 2 "chunks" of information. Chunking (e.g., grouping digits into area codes) allows more information to be held within this limit. Modern estimates suggest the limit may be closer to 4 chunks.` },
      { q:`Vygotsky's concept of the zone of proximal development (ZPD) refers to:`, ch:[`Skills a child can demonstrate independently`,`The range between what a child can do alone and what they can do with guidance`,`The developmental delay caused by lack of stimulation`,`Piaget's stage of formal operations`], ans:1, exp:`ZPD: the difference between what a learner can accomplish independently and what they can accomplish with guidance from a more skilled person (scaffolding). Learning occurs most efficiently within this zone — tasks not too easy, not too hard.` },
      { q:`Which memory system stores facts and general knowledge about the world?`, ch:[`Procedural memory`,`Episodic memory`,`Semantic memory`,`Working memory`], ans:2, exp:`Semantic memory: general factual knowledge not tied to personal experience (e.g., knowing Paris is the capital of France, what a dog is). Episodic memory stores autobiographical events. Procedural memory stores how to perform skills.` },
      { q:`Observational learning (modeling) was demonstrated by Bandura through the:`, ch:[`Little Albert experiment`,`Bobo doll experiment`,`Stanford prison experiment`,`Milgram obedience study`], ans:1, exp:`Bandura's Bobo doll experiments showed children imitated aggressive behaviors they observed adults performing toward the doll. This established that learning can occur through observation alone (without direct reinforcement), forming the basis of social learning theory.` },
      { q:`Harlow's rhesus monkey experiments showed that attachment is primarily based on:`, ch:[`Food provision`,`Contact comfort and warmth`,`Genetic relatedness`,`Reinforcement schedules`], ans:1, exp:`Harlow's monkeys preferred a cloth "mother" (contact comfort) over a wire "mother" that provided food. This demonstrated that attachment is based primarily on tactile comfort rather than food, challenging the behavioral view that attachment is learned through feeding.` },
      { q:`Proactive interference in memory occurs when:`, ch:[`New learning interferes with recall of old information`,`Old learning interferes with recall of new information`,`Traumatic experiences block all memory formation`,`Sleep deprivation prevents memory consolidation`], ans:1, exp:`Proactive interference: previously learned information interferes with recall of newly learned information. (Retroactive interference is the reverse: new information interferes with old.) Both can explain everyday forgetting.` },
      { q:`Attachment theory (Bowlby) proposes that secure attachment in infancy:`, ch:[`Has no effect on adult relationships`,`Is based on feeding and nourishment`,`Provides a secure base for exploration and is associated with positive adult relationship patterns`,`Leads to increased independence and avoidance of relationships`], ans:2, exp:`Secure attachment (Bowlby, Ainsworth): infants with consistent, responsive caregivers develop a secure base for exploration. Secure attachment predicts positive outcomes: better social competence, lower anxiety, and healthier adult relationships (internal working models).` },
      { q:`The serial position effect in free recall refers to:`, ch:[`Better recall of middle list items`,`Better recall of first (primacy) and last (recency) items in a list`,`Worse recall for emotionally charged items`,`Equal recall across all list positions`], ans:1, exp:`Serial position effect: items at the beginning (primacy — transferred to long-term memory during rehearsal) and end (recency — still in working memory) of a list are recalled better than items in the middle. This provides evidence for separate short- and long-term memory stores.` },
    ]
  },
  {
    id:'ps03', cat:'Psych/Soc', title:'Sociology, Research Methods & Statistics', diff:'Medium',
    qs:[
      { q:`Social stratification refers to:`, ch:[`Random variation in social status`,`The hierarchical ranking of groups in society based on wealth, power, or prestige`,`The process of social mobility`,`Discrimination based on race`], ans:1, exp:`Social stratification: the systematic hierarchical ranking of individuals or groups based on socioeconomic factors (wealth, income), power, and social prestige. Systems include caste (ascribed, rigid), class (achieved, flexible), and estate systems.` },
      { q:`The social determinants of health include all of the following EXCEPT:`, ch:[`Income and social status`,`Education level`,`Genetic mutations in tumor suppressor genes`,`Social support networks and community`], ans:2, exp:`Social determinants of health (WHO): social and economic conditions that influence health (income, education, employment, social support, built environment, healthcare access). Genetic mutations are biological, not social, determinants. Both matter for health outcomes.` },
      { q:`A randomized controlled trial (RCT) differs from an observational study in that:`, ch:[`RCTs are cheaper to conduct`,`RCTs randomly assign subjects to experimental and control groups, controlling for confounders`,`RCTs only involve surveys`,`RCTs cannot establish causality`], ans:1, exp:`RCTs: random assignment to experimental and control conditions controls for confounding variables (both known and unknown), allowing causal inference. Observational studies can identify associations but cannot definitively establish causation.` },
      { q:`Reliability in research refers to:`, ch:[`Whether a measure actually measures what it claims to measure`,`The consistency of a measure across repeated testing (test-retest) or raters (inter-rater)`,`The generalizability of findings to the population`,`The absence of systematic bias`], ans:1, exp:`Reliability = consistency. A bathroom scale is reliable if it gives the same reading each time for the same object. Validity = accuracy (does it measure what you intend?). A scale can be reliable but invalid (consistently off by 5 lbs).` },
      { q:`A p-value of 0.03 in a study means:`, ch:[`There is a 3% chance the hypothesis is true`,`The probability of observing results as extreme as these (or more) if the null hypothesis is true is 3%`,`The effect size is large`,`The results are clinically significant`], ans:1, exp:`P-value: the probability of observing results at least as extreme as the data, assuming the null hypothesis is true. p=0.03 < 0.05 threshold = statistically significant (reject null). P-value does NOT indicate the probability that the null hypothesis is true or false.` },
      { q:`The incidence rate measures:`, ch:[`The total number of cases in a population at a given time`,`The number of new cases of a disease occurring in a population over a specific time period`,`The ratio of cases in exposed vs unexposed groups`,`The probability of death given diagnosis`], ans:1, exp:`Incidence = new cases per population per time. Prevalence = total existing cases (new + old) per population at a specific time. Incidence × duration ≈ prevalence (for stable conditions). High incidence with short duration gives low prevalence.` },
      { q:`Socialization is the process by which:`, ch:[`Individuals form small social groups`,`People internalize society's norms, values, and roles`,`Societies create laws and enforce them`,`Social stratification is maintained`], ans:1, exp:`Socialization: the lifelong process through which individuals learn and internalize the norms, values, beliefs, and behaviors of their society. Primary socialization occurs in childhood (family); secondary socialization occurs through schools, peers, media, religion.` },
      { q:`The difference between Type I and Type II errors in hypothesis testing is:`, ch:[`Type I: false negative; Type II: false positive`,`Type I: false positive (rejecting true null); Type II: false negative (failing to reject false null)`,`Both are false positives`,`Type I concerns effect size; Type II concerns sample size`], ans:1, exp:`Type I error (alpha): false positive — rejecting the null hypothesis when it is actually true. Type II error (beta): false negative — failing to reject the null hypothesis when it is actually false. Statistical power = 1 - beta = probability of correctly detecting a true effect.` },
      { q:`In a cross-sectional study, data are collected:`, ch:[`Over many years to track the same cohort`,`At a single point in time from a population snapshot`,`From exposed and unexposed groups followed forward`,`From cases and controls matched for age and gender`], ans:1, exp:`Cross-sectional studies measure exposure and outcome simultaneously (snapshot). They can establish prevalence and associations but cannot determine temporality (which came first?) or causation. Cohort studies follow subjects forward; case-control studies look backward from outcome.` },
      { q:`Relative risk (RR) is best described as:`, ch:[`The probability of disease in the exposed group`,`The risk of disease in the exposed group divided by the risk in the unexposed group`,`The difference in risk between exposed and unexposed groups`,`The odds of exposure in cases vs controls`], ans:1, exp:`Relative risk = (incidence in exposed) / (incidence in unexposed). RR=2 means the exposed group has twice the risk. Used in cohort studies. Odds ratio (OR) is used in case-control studies and approximates RR when the disease is rare.` },
      { q:`Absolute poverty differs from relative poverty in that:`, ch:[`Absolute poverty is more common in developed countries`,`Absolute poverty measures deprivation relative to societal median income`,`Absolute poverty represents a fixed standard of minimum resources needed for survival`,`Relative poverty is more severe`], ans:2, exp:`Absolute poverty: inability to meet a fixed threshold of basic needs (food, shelter, water). Relative poverty: income/resources below a threshold relative to the median in a given society (e.g., 50% of median income). Relative poverty is more relevant in developed nations; absolute poverty in developing ones.` },
      { q:`The ecological fallacy occurs when:`, ch:[`Research is conducted only in ecological settings`,`Conclusions about individuals are incorrectly drawn from group-level data`,`Experimental results fail to replicate`,`Control groups are not properly matched`], ans:1, exp:`The ecological fallacy: inferring individual-level relationships from group-level (aggregate) data. Example: countries with higher fat consumption have higher heart disease rates (aggregate), but this does not necessarily mean fat consumption causes heart disease at the individual level.` },
      { q:`Ethnocentrism is the tendency to:`, ch:[`Study other cultures objectively`,`Evaluate other cultures using the standards of one's own culture as a baseline`,`Adopt the values of other cultures`,`Avoid making cultural judgments`], ans:1, exp:`Ethnocentrism: judging other cultures by the standards and values of one's own culture. The opposite is cultural relativism — understanding cultural practices within their own cultural context without external judgment. Both ethnocentrism and xenocentrism (favoring other cultures) are biases.` },
      { q:`Hawthorne effect in research refers to:`, ch:[`Placebo responses to treatment`,`Subjects changing their behavior because they know they are being observed or studied`,`Researcher bias in data collection`,`Loss of subjects over time in longitudinal studies`], ans:1, exp:`Hawthorne effect: subjects modify their behavior when aware of being observed, independent of the experimental manipulation. Named after studies at the Hawthorne Works factory. It is a form of reactivity that can confound research results.` },
      { q:`The coefficient of variation (CV) measures:`, ch:[`The correlation between two variables`,`The relative spread of data (standard deviation / mean × 100%)`,`The difference between median and mean`,`The probability of a given outcome`], ans:1, exp:`CV = (SD / mean) × 100%. It is a dimensionless measure of relative dispersion, useful for comparing variability across datasets with different units or means. A low CV indicates low relative variability; a high CV indicates high variability relative to the mean.` },
    ]
  },
];
